-- #############################################################################
-- VALIDATION QUERIES (uncomment to run)
-- #############################################################################
/*
-- Scenario A: Inventory Misallocation
-- Expected: WH1 CORRECT, WH2 SHORT -105, WH3 OVER +57, WH4 OVER +48, WH5 CORRECT
SELECT w.ID, w.NAME, sl.QUANTITY AS shipped, inv.QUANTITY_ON_HAND AS actual,
    inv.QUANTITY_ON_HAND - sl.QUANTITY AS delta,
    CASE WHEN inv.QUANTITY_ON_HAND - sl.QUANTITY = 0 THEN 'CORRECT'
         WHEN inv.QUANTITY_ON_HAND - sl.QUANTITY < 0 THEN 'SHORT'
         ELSE 'OVER' END AS status
FROM RET_SHIPMENTS s
JOIN RET_SHIPMENT_LINES sl ON s.ID = sl.SHIPMENT_ID
JOIN RET_WAREHOUSES w ON s.DESTINATION_WAREHOUSE_ID = w.ID
JOIN RET_INVENTORY inv ON inv.PRODUCT_ID = sl.PRODUCT_ID AND inv.WAREHOUSE_ID = w.ID
WHERE sl.PRODUCT_ID = 42 AND s.DEMO_BATCH_ID = 'DEMO_2026_SCENARIOS'
ORDER BY w.ID;

-- Scenario B: Faulty Products (>20% defective return rate)
-- Expected: Products 101, 102, 103 FLAGGED; 104, 105 OK (near-miss); 106-108 OK (clean)
WITH sales AS (
    SELECT oi.PRODUCT_ID, COUNT(*) AS units_sold
    FROM RET_ORDER_ITEMS oi JOIN RET_ORDERS o ON oi.ORDER_ID = o.ID
    WHERE o.STATUS = 'delivered' AND o.ORDER_DATE >= DATEADD('day', -365, '2026-06-01')
      AND oi.DEMO_BATCH_ID = 'DEMO_2026_SCENARIOS'
    GROUP BY oi.PRODUCT_ID
),
defective_returns AS (
    SELECT r.PRODUCT_ID, COUNT(*) AS defective_units
    FROM RET_RETURNS r
    WHERE r.RETURN_REASON = 'Defective' AND r.RETURN_DATE >= DATEADD('day', -365, '2026-06-01')
      AND r.DEMO_BATCH_ID = 'DEMO_2026_SCENARIOS'
    GROUP BY r.PRODUCT_ID
)
SELECT s.PRODUCT_ID, p.NAME, v.NAME AS vendor, s.units_sold,
    COALESCE(d.defective_units, 0) AS defective_returns,
    ROUND(COALESCE(d.defective_units, 0) * 100.0 / s.units_sold, 1) AS defect_rate_pct,
    CASE WHEN COALESCE(d.defective_units, 0) * 100.0 / s.units_sold > 20 THEN 'FLAGGED' ELSE 'OK' END AS status
FROM sales s
JOIN RET_PRODUCTS p ON s.PRODUCT_ID = p.ID
LEFT JOIN RET_VENDORS v ON p.VENDOR_ID = v.ID
LEFT JOIN defective_returns d ON s.PRODUCT_ID = d.PRODUCT_ID
WHERE s.PRODUCT_ID BETWEEN 101 AND 108
ORDER BY defect_rate_pct DESC;

-- Scenario C: Customer Segmentation
-- Expected: 401-403 VIP, 404-405 BigSpend, 406-408 CatLoyal, 409 All, 410 VIP+BS, 411-415 excluded
WITH order_level AS (
    SELECT CUSTOMER_ID, WAREHOUSE_ID, COUNT(*) AS txn_count, AVG(TOTAL_AMOUNT) AS avg_val, MAX(TOTAL_AMOUNT) AS max_val
    FROM RET_ORDERS
    WHERE STATUS = 'delivered' AND ORDER_DATE >= DATEADD('day', -180, '2026-06-01')
      AND _FIVETRAN_DELETED = FALSE AND DEMO_BATCH_ID = 'DEMO_2026_SCENARIOS' AND ID BETWEEN 91001 AND 91399
    GROUP BY CUSTOMER_ID, WAREHOUSE_ID
),
category_loyalty AS (
    SELECT o.CUSTOMER_ID, sc.CATEGORY_ID, COUNT(*) AS cat_txn_count
    FROM RET_ORDERS o
    JOIN RET_ORDER_ITEMS oi ON o.ID = oi.ORDER_ID
    JOIN RET_PRODUCTS p ON oi.PRODUCT_ID = p.ID
    JOIN RET_PRODUCT_SUBCATEGORIES sc ON p.SUBCATEGORY_ID = sc.ID
    WHERE o.STATUS = 'delivered' AND o.ORDER_DATE >= DATEADD('day', -180, '2026-06-01')
      AND o._FIVETRAN_DELETED = FALSE AND oi._FIVETRAN_DELETED = FALSE
      AND o.DEMO_BATCH_ID = 'DEMO_2026_SCENARIOS' AND o.ID BETWEEN 91001 AND 91399
    GROUP BY o.CUSTOMER_ID, sc.CATEGORY_ID HAVING COUNT(*) >= 10
)
SELECT ol.CUSTOMER_ID, ol.txn_count, ROUND(ol.avg_val, 2) AS avg_txn_value, ol.max_val,
    CASE WHEN ol.avg_val > 100 AND ol.txn_count >= 3 THEN 'Y' ELSE 'N' END AS is_vip,
    CASE WHEN ol.max_val > 300 THEN 'Y' ELSE 'N' END AS is_big_spender,
    CASE WHEN cl.CUSTOMER_ID IS NOT NULL THEN 'Y' ELSE 'N' END AS is_category_loyal
FROM order_level ol
LEFT JOIN category_loyalty cl ON ol.CUSTOMER_ID = cl.CUSTOMER_ID
ORDER BY ol.CUSTOMER_ID;
*/


