  ('TBD_RV_000000', 4000, 101, 1, 1, 'Started leaking after a week', 'Installed this Dolta faucet and within days it started dripping. Very disappointed. Had to call a plumber to remove it. Will not buy Dolta again from TBD.', TRUE, '2026-05-15 00:00:00.000', FALSE, '2026-05-15 12:00:00.000 -0700'),
